module top_module(
    input clk,
    input load,
    input [1:0] ena,
    input [99:0] data,
    input a,
    input b,
    output out
);reg [99:0] flip_flop;
wire [99:0] shifted_data;

// Shift register module
always @(posedge clk) begin
    if (load) begin
        flip_flop <= data;
    end else if (ena == 2'b01) begin
        flip_flop <= {flip_flop[0], flip_flop[99:1]};
    end else if (ena == 2'b10) begin
        flip_flop <= {flip_flop[98:0], flip_flop[99]};
    end
end

assign shifted_data = flip_flop;

// NOR gate module
assign out = ~(a | b);

endmodule
